  ('BHP Xplor', '9-month accelerator for critical minerals exploration. Up to US$500K equity-free funding per company. 21 alumni companies since 2023.', 'vc', 'Australia', 'https://www.bhp.com/what-we-do/xplor', 'bhp-xplor', 'Australia', ARRAY['Deep Tech']::text[], ARRAY['technology-information-and-media', 'professional-services', 'manufacturing']::text[], false),
  ('Cartier Women''s Initiative', 'International award programme backing women-founded, for-profit businesses with social or environmental impact. Fellows receive USD $30,000 to $100,000 equity-free, plus mentoring, global visibility, and a year-long fellowship. Nine regional awards (including Oceania for Australian founders) plus a Science and Technology Pioneer Award. Requires annual revenue USD $50,000–$5 million, team of 5–250 (including contractors), and no more than USD $2 million dilutive funding raised. Science and Tech track excludes AI applications built on third-party models.', 'grant', 'Australia', 'https://www.cartierwomensinitiative.com/', 'cartier-women-s-initiative', 'Australia', '{}'::text[], '{}'::text[], true),
  ('Croc Pitch', 'Northern Australia''s largest startup pitch competition, run by the Darwin Innovation Hub. Winner receives up to $1M in Paspalis venture capital. Annual event each September.', 'grant', 'Darwin, NT', 'https://crocpitch.com.au/', 'croc-pitch', 'Australia', ARRAY['Technology']::text[], ARRAY['technology-information-and-media']::text[], false),
