  ('HCF Catalyst', 'Australia''s largest health insurer''s accelerator for healthtech startups. Pilot opportunities with HCF''s 1.9M members.', 'vc', 'Australia', 'https://www.hcf.com.au/', 'hcf-catalyst', 'Australia', ARRAY['HealthTech']::text[], ARRAY['hospitals-and-health-care', 'technology-information-and-media']::text[], false),
