  ('Smart50 Awards', 'SmartCompany''s annual awards for Australia''s fastest-growing SMEs. Categories include innovation and emerging entrepreneur.', 'grant', 'Australia', 'https://smart50awards.com.au/', 'smart50-awards', 'Australia', ARRAY['Technology']::text[], ARRAY['technology-information-and-media']::text[], false),
  ('Startup World Cup - Australia', 'Regional qualifiers feeding into the US$1M global pitch final in San Francisco. Australian rounds in Melbourne and Sydney.', 'grant', 'Australia', 'https://www.startupandangels.com/startup-world-cup-australia/', 'startup-world-cup-australia', 'Australia', ARRAY['Technology']::text[], ARRAY['technology-information-and-media']::text[], false),
