  ('Australian Network on Disability', 'Membership organisation connecting employers and businesses to disability inclusion best practices.', 'Australia', '', '', 'https://www.and.org.au/', 'australian-network-on-disability', ARRAY['Industry Body']::text[], '{}'::text[], '{}'::text[], true),
